from decimal import Decimal
from datetime import date
from app.database import SessionLocal, engine
from app.models import Base, Departamento, Colaborador, RegistroCusto, ComponenteCusto

Base.metadata.create_all(bind=engine)
db = SessionLocal()

dep_nomes = ['Desenvolvimento','Comercial','Marketing','CoE','Projetos','Nuvem Gerenciada']
deps = {}
for nome in dep_nomes:
    d = db.query(Departamento).filter(Departamento.nome == nome).first()
    if not d:
        d = Departamento(nome=nome); db.add(d); db.flush()
    deps[nome] = d.id
db.commit()
print('Departamentos:', deps)

_seq = {}
_cols = {}

def mat(nome):
    s = nome.strip().upper().replace(' ','')[:8]
    _seq[s] = _seq.get(s,0)+1
    return s + (str(_seq[s]) if _seq[s]>1 else '')

def col(nome, dep, cargo):
    if nome in _cols: return _cols[nome]
    did = deps.get(dep)
    if not did: return None
    tipo = 'PJ' if cargo.upper()=='PJ' else 'CLT'
    c = db.query(Colaborador).filter(Colaborador.nome==nome).first()
    if not c:
        c = Colaborador(nome=nome, matricula=mat(nome), departamento_id=did,
            cargo='Colaborador PJ' if tipo=='PJ' else cargo,
            tipo_contrato=tipo, data_admissao=date(2020,1,1), ativo=True)
        db.add(c); db.flush()
    _cols[nome] = c; return c

def add(m,a,nome,dep,cargo,rem,ref,tra,ss,sv,fg,gp,eq,es,fe,d3,f2,g2,mf,tot):
    c = col(nome,dep,cargo)
    if not c: return
    if db.query(RegistroCusto).filter_by(colaborador_id=c.id,mes=m,ano=a).first(): return
    r = RegistroCusto(colaborador_id=c.id,mes=m,ano=a); db.add(r); db.flush()
    for t,v in [('remuneracao',rem),('refeicao',ref),('transporte',tra),
                ('seguro_saude',ss),('seguro_vida',sv),('fgts',fg),('gps',gp),
                ('equipamentos',eq),('escritorio',es),('ferias',fe),
                ('decimo_terceiro',d3),('fgts_rescisao',f2),('gps_rescisao',g2),('multa_fgts',mf)]:
        if v and float(v)>0:
            db.add(ComponenteCusto(registro_custo_id=r.id,tipo=t,valor=Decimal(str(round(float(v),2)))))
